// HMAC-SHA256 en JS puro (n8n task runner: sin require ni crypto global; solo Buffer).
function sha256Bytes(bytes) {
  const K = [0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
  let h0=0x6a09e667,h1=0xbb67ae85,h2=0x3c6ef372,h3=0xa54ff53a,h4=0x510e527f,h5=0x9b05688c,h6=0x1f83d9ab,h7=0x5be0cd19;
  const msg = bytes.slice();
  const origLenBits = msg.length * 8;
  msg.push(0x80);
  while (msg.length % 64 !== 56) msg.push(0x00);
  const hi = Math.floor(origLenBits / 0x100000000);
  const lo = origLenBits >>> 0;
  msg.push((hi>>>24)&0xff,(hi>>>16)&0xff,(hi>>>8)&0xff,hi&0xff);
  msg.push((lo>>>24)&0xff,(lo>>>16)&0xff,(lo>>>8)&0xff,lo&0xff);
  function rotr(x,n){ return (x>>>n)|(x<<(32-n)); }
  for (let i=0;i<msg.length;i+=64){
    const w=new Array(64);
    for(let t=0;t<16;t++){ w[t]=((msg[i+t*4]<<24)|(msg[i+t*4+1]<<16)|(msg[i+t*4+2]<<8)|(msg[i+t*4+3]))>>>0; }
    for(let t=16;t<64;t++){
      const s0=rotr(w[t-15],7)^rotr(w[t-15],18)^(w[t-15]>>>3);
      const s1=rotr(w[t-2],17)^rotr(w[t-2],19)^(w[t-2]>>>10);
      w[t]=(w[t-16]+s0+w[t-7]+s1)>>>0;
    }
    let a=h0,b=h1,c=h2,d=h3,e=h4,f=h5,g=h6,h=h7;
    for(let t=0;t<64;t++){
      const S1=rotr(e,6)^rotr(e,11)^rotr(e,25);
      const ch=(e&f)^((~e)&g);
      const temp1=(h+S1+ch+K[t]+w[t])>>>0;
      const S0=rotr(a,2)^rotr(a,13)^rotr(a,22);
      const maj=(a&b)^(a&c)^(b&c);
      const temp2=(S0+maj)>>>0;
      h=g;g=f;f=e;e=(d+temp1)>>>0;d=c;c=b;b=a;a=(temp1+temp2)>>>0;
    }
    h0=(h0+a)>>>0;h1=(h1+b)>>>0;h2=(h2+c)>>>0;h3=(h3+d)>>>0;h4=(h4+e)>>>0;h5=(h5+f)>>>0;h6=(h6+g)>>>0;h7=(h7+h)>>>0;
  }
  const hs=[h0,h1,h2,h3,h4,h5,h6,h7]; const out=[];
  for(const x of hs){ out.push((x>>>24)&0xff,(x>>>16)&0xff,(x>>>8)&0xff,x&0xff); }
  return out;
}
function hmacSha256Hex(keyStr, msgStr){
  const block=64;
  let key=Array.from(Buffer.from(keyStr,'utf8'));
  if(key.length>block) key=sha256Bytes(key);
  if(key.length<block) key=key.concat(new Array(block-key.length).fill(0));
  const ipad=key.map(function(b){return b^0x36;});
  const opad=key.map(function(b){return b^0x5c;});
  const msg=Array.from(Buffer.from(msgStr,'utf8'));
  const inner=sha256Bytes(ipad.concat(msg));
  const outer=sha256Bytes(opad.concat(inner));
  return outer.map(function(b){return b.toString(16).padStart(2,'0');}).join('');
}

const item = $input.first();

// 1) Body crudo
let raw = '';
if (item.binary && item.binary.data && item.binary.data.data) {
  raw = Buffer.from(item.binary.data.data, 'base64').toString('utf8');
} else if (typeof item.json.body === 'string') {
  raw = item.json.body;
} else if (item.json.body) {
  raw = JSON.stringify(item.json.body);
}

const headers = item.json.headers || {};
const header_sig = headers['x-hub-signature-256'] || '';
const appSecret = $env.WHATSAPP_APP_SECRET || '';

// 2) Firma
const computed_signature = hmacSha256Hex(appSecret, raw);
const valid = header_sig.length > 0 && ('sha256=' + computed_signature) === header_sig;

// 3) Parsear payload
let payload = {};
try { payload = JSON.parse(raw); } catch(e) { payload = (typeof item.json.body === 'object' ? item.json.body : {}); }
const change = (((payload.entry || [])[0] || {}).changes || [])[0] || {};
const value = change.value || {};
const msg = (value.messages || [])[0] || null;
const is_message = !!msg;
const from = msg ? (msg.from || '') : '';
const phone_number_id = (value.metadata || {}).phone_number_id || '';

// 4) Enriquecer: tipo, texto, interactive (boton/lista), imagen
let msg_type = msg ? (msg.type || '') : '';
let text = '';
let interactive_id = '';
let interactive_title = '';
let image_id = '';
let msg_text = '';
if (msg) {
  if (msg.type === 'text') { text = (msg.text || {}).body || ''; msg_text = text; }
  else if (msg.type === 'interactive') {
    const it = msg.interactive || {};
    if (it.type === 'button_reply') { interactive_id = (it.button_reply || {}).id || ''; interactive_title = (it.button_reply || {}).title || ''; }
    else if (it.type === 'list_reply') { interactive_id = (it.list_reply || {}).id || ''; interactive_title = (it.list_reply || {}).title || ''; }
    msg_text = interactive_title || interactive_id;
  }
  else if (msg.type === 'image') { image_id = (msg.image || {}).id || ''; msg_text = '[imagen]'; }
  else { msg_text = '[' + (msg.type || 'desconocido') + ']'; }
}

return [{ json: { valid, computed_signature, header_sig, is_message, from, phone_number_id, msg_type, text, interactive_id, interactive_title, image_id, msg_text, message_id: msg ? (msg.id || '') : '' } }];

// CEREBRO DE LA MAQUINA DE ESTADOS. Tabla de transiciones en un solo lugar (versionable).
// Lee: mensaje parseado (Validar y Parsear) + estado actual (Cargar Estado).
// Decide: action (responder|buscar|registrar|foto), next_paso, patch (campos a persistir) y wa_payload.
const p = $('Validar y Parsear').item.json;
const row = ($json && $json.celular) ? $json : {};
const from = p.from || '';
const celular10 = from.replace(/^57/, '');
const hadRow = !!(row && row.celular);
const paso = hadRow ? (row.paso || 'inicio') : 'inicio';
const text = (p.text || '').trim();
const btn = p.interactive_id || '';
const type = p.msg_type || '';

function txt(body){ return { messaging_product:'whatsapp', to: from, type:'text', text:{ body: body, preview_url:false } }; }
function buttons(body, arr){ return { messaging_product:'whatsapp', to: from, type:'interactive', interactive:{ type:'button', body:{ text: body }, action:{ buttons: arr.map(function(b){ return { type:'reply', reply:{ id:b.id, title:b.title } }; }) } } }; }
function listMsg(body, rows){ return { messaging_product:'whatsapp', to: from, type:'interactive', interactive:{ type:'list', body:{ text: body }, action:{ button:'Elegir', sections:[ { title:'Opciones', rows: rows } ] } } }; }

const OCU = [ {id:'ocupacion_1',title:'Ocupación 1'},{id:'ocupacion_2',title:'Ocupación 2'},{id:'ocupacion_3',title:'Ocupación 3'},{id:'ocupacion_4',title:'Ocupación 4'} ];

let out = { action:'responder', wa_to: from, wa_payload: null, next_paso: paso, patch: {}, celular: from, celular10: celular10, had_row: hadRow, search_query: null, search_by: null, image_id: '' };

switch (paso) {
  case 'esperando_correo': {
    const email = text.toLowerCase();
    const ok = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
    if (!ok) { out.wa_payload = txt('Ese correo no parece válido. Escríbeme tu correo, por favor (ejemplo: nombre@correo.com).'); out.next_paso='esperando_correo'; out.patch={ paso:'esperando_correo' }; }
    else { out.action='buscar'; out.search_by='email'; out.search_query={ email: email }; out.patch={ correo: email, distinct_id: email }; }
    break;
  }
  case 'esperando_nombre': {
    if (!text) { out.wa_payload = txt('Necesito tu nombre completo para continuar. Escríbelo, por favor.'); out.next_paso='esperando_nombre'; out.patch={ paso:'esperando_nombre' }; }
    else { out.wa_payload = txt('Gracias. Ahora escríbeme tu número de cédula (solo números).'); out.next_paso='esperando_cedula'; out.patch={ nombre: text, paso:'esperando_cedula' }; }
    break;
  }
  case 'esperando_cedula': {
    const ced = text.replace(/\D/g,'');
    if (ced.length < 5) { out.wa_payload = txt('La cédula debe ser numérica. Escríbela de nuevo, por favor.'); out.next_paso='esperando_cedula'; out.patch={ paso:'esperando_cedula' }; }
    else { out.wa_payload = listMsg('¿Cuál es tu ocupación? Elige una opción.', OCU); out.next_paso='esperando_ocupacion'; out.patch={ cedula: ced, paso:'esperando_ocupacion' }; }
    break;
  }
  case 'esperando_ocupacion': {
    if (['ocupacion_1','ocupacion_2','ocupacion_3','ocupacion_4'].indexOf(btn) === -1) { out.wa_payload = listMsg('Elige tu ocupación de la lista, por favor.', OCU); out.next_paso='esperando_ocupacion'; out.patch={ paso:'esperando_ocupacion' }; }
    else {
      const resumen = 'Confirmemos tus datos:\n\n' + 'Nombre: ' + (row.nombre||'') + '\n' + 'Cédula: ' + (row.cedula||'') + '\n' + 'Correo: ' + (row.correo||'') + '\n' + 'Celular: ' + celular10 + '\n\n¿Es correcto?';
      out.wa_payload = buttons(resumen, [ {id:'confirmar_si',title:'Sí, registrar'}, {id:'confirmar_no',title:'No, corregir'} ]);
      out.next_paso='esperando_confirmacion';
      out.patch={ ocupacion: btn, tags: ['grupo_1'], paso:'esperando_confirmacion' };
    }
    break;
  }
  case 'esperando_confirmacion': {
    if (btn === 'confirmar_si') { out.action='registrar'; out.patch={ paso:'registrando' }; }
    else if (btn === 'confirmar_no') { out.wa_payload = txt('Sin problema, empecemos de nuevo. Escríbeme tu nombre completo.'); out.next_paso='esperando_nombre'; out.patch={ paso:'esperando_nombre' }; }
    else { out.wa_payload = buttons('¿Confirmas tus datos?', [ {id:'confirmar_si',title:'Sí, registrar'}, {id:'confirmar_no',title:'No, corregir'} ]); out.next_paso='esperando_confirmacion'; out.patch={ paso:'esperando_confirmacion' }; }
    break;
  }
  case 'esperando_foto': {
    if (type === 'image') { out.action='foto'; out.image_id = p.image_id || ''; out.patch={ paso:'procesando' }; }
    else { out.wa_payload = txt('Por favor envíame la *foto* de tu factura para registrar tu compra y ganar puntos.'); out.next_paso='esperando_foto'; out.patch={ paso:'esperando_foto' }; }
    break;
  }
  case 'esperando_csat': {
    const n = parseInt(((text||btn)||'').replace(/\D/g,''), 10);
    if (n >= 1 && n <= 5) { out.wa_payload = txt('¡Gracias por tu calificación! 🙏 Cuando quieras registrar otro ticket, envíame la foto.'); out.next_paso='finalizado'; out.patch={ paso:'finalizado', datos: Object.assign({}, row.datos||{}, { csat: n }) }; }
    else { out.wa_payload = txt('Calíficanos del 1 al 5, por favor (solo el número).'); out.next_paso='esperando_csat'; out.patch={ paso:'esperando_csat' }; }
    break;
  }
  case 'finalizado': {
    if (type === 'image') { out.action='foto'; out.image_id = p.image_id || ''; out.patch={ paso:'procesando' }; }
    else { out.wa_payload = txt('¿Quieres registrar otro ticket? Envíame la foto de la factura cuando quieras. 📸'); out.next_paso='esperando_foto'; out.patch={ paso:'esperando_foto' }; }
    break;
  }
  case 'buscando':
  case 'registrando':
  case 'procesando': {
    out.wa_payload = txt('Dame un segundo, estoy procesando tu solicitud… ⏳'); out.next_paso = paso; out.patch = {};
    break;
  }
  default: {
    out.action='buscar'; out.search_by='cellphone'; out.search_query={ cellphone: celular10 };
    out.patch={ paso:'buscando', celular: from, intentos: 0 };
  }
}

if (out.action === 'buscar' && out.search_query) {
  const BASE = 'https://api.superlikerslabs.com/v1';
  const apiKey = encodeURIComponent($env.API_KEY || '');
  let qs = 'api_key=' + apiKey + '&campaign=3z';
