else if (resp && resp.participant) participant = resp.participant;
else if (resp && resp.data) participant = Array.isArray(resp.data) ? (resp.data[0]||{}) : resp.data;
else if (resp && Array.isArray(resp.participants)) participant = resp.participants[0] || {};
else if (Array.isArray(resp)) participant = resp[0] || {};
const found = status === 200 && !!(participant && (participant.email || participant.distinct_id || participant.points !== undefined || participant['nombre-completo']));
function txt(body){ return { messaging_product:'whatsapp', to: from, type:'text', text:{ body: body, preview_url:false } }; }
let out = { action:'responder', wa_to: from, wa_payload: null, next_paso:'', patch:{}, celular: d.celular, had_row: d.had_row };
