// A6 · Prep IA v6 — gpt-5.4-mini + prompt mejorado para columnas de precio
const FACTURA_SYSTEM = "Eres un asistente que extrae informacion de facturas/recibos de compra a partir de una imagen. Devuelve UNICAMENTE un objeto JSON valido, sin texto adicional, sin explicaciones y sin bloques de codigo markdown.\\n\\nEstructura exacta a devolver:\\n{\\n  \\\"legible\\\": true,\\n  \\\"ref\\\": \\\"<numero de factura>\\\",\\n  \\\"products\\\": [\\n    { \\\"ref\\\": \\\"<codigo o nombre>\\\", \\\"price\\\": \\\"<precio unitario>\\\", \\\"quantity\\\": \\\"<cantidad>\\\", \\\"line\\\": \\\"<linea>\\\", \\\"provider\\\": \\\"<proveedor>\\\" }\\n  ]\\n}\\n\\nReglas:\\n- ref = numero de la factura o recibo. Busca etiquetas como: Factura, No., Nro, N\u00b0, Ticket, POS, Consecutivo, CUFE. Devuelvelo tal cual aparece.\\n- price = precio UNITARIO de cada producto (lo que cuesta UNA unidad). En facturas con columnas como [cantidad | precio_unitario | codigo | descripcion | total_linea], extrae la segunda columna numerica (precio unitario), NO el total de la linea ni el codigo de barras. Ignora separadores de miles (puntos o comas). Devuelve solo digitos y punto decimal si aplica.\\n- quantity = numero de unidades o peso. Solo el valor numerico, sin texto como 'UN', 'KG', 'Kg'.\\n- Solo si NO hay numero de factura visible, o la imagen no es una factura, devuelve legible=false con ref vacio y products vacio.\\n- line y provider: si no aparecen, usa string vacio. No inventes datos.\\n";
const SCHEMA = { name:'factura', strict:true, schema:{
  type:'object', additionalProperties:false,
  properties:{
    legible:{ type:'boolean' },
    ref:{ type:'string' },
    products:{ type:'array', items:{
      type:'object', additionalProperties:false,
      properties:{ ref:{type:'string'}, price:{type:'string'}, quantity:{type:'string'}, line:{type:'string'}, provider:{type:'string'} },
      required:['ref','price','quantity','line','provider'] } }
  },
  required:['legible','ref','products'] } };

const d = $('Decidir').first().json;
let media_ok = true, b64 = '', mime = 'image/jpeg';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
