if (typeof photosRaw.data === 'string') { try { photos = JSON.parse(photosRaw.data); } catch(e){ photos = photosRaw; } }
const prep = $('A6 · Prep IA').first().json || {};
const ai  = $('A6 · Leer Factura (IA)').first().json || {};

const photoObj = photos.object || photos;
let id_actividad_foto =
  photoObj.id || photoObj._id || photoObj.entry_id ||
  photoObj.activity_id || photoObj.entry || photoObj.photo_id || '';
if (!id_actividad_foto && photos.image_url) {
  const m = (photos.image_url || '').match(/upload-photo\/([a-f0-9]{24})\//i);
  if (m) id_actividad_foto = m[1];
}

const photosBlob = JSON.stringify(photosRaw).toLowerCase();
const sha1_dup   = photosBlob.indexOf('sha1') !== -1 && photosBlob.indexOf('taken') !== -1;
const media_ok   = prep.media_ok !== false;

let parsed = { legible:false, ref:'', products:[] };
try {
  const content = (((ai.choices||[])[0]||{}).message||{}).content || '';
  parsed = JSON.parse(content);
} catch(e) { parsed = { legible:false, ref:'', products:[] }; }

const ref_raw  = (parsed.ref || '').toString().trim();
const ref_norm = ref_raw.replace(/\D/g, '') || ref_raw.replace(/\s+/g,'').toUpperCase();
const ref      = ref_norm;

const products = Array.isArray(parsed.products) ? parsed.products : [];
const legible  = parsed.legible === true && ref !== '' && products.length > 0;

let outcome;
if (!media_ok)    outcome = 'reintentar';
else if (sha1_dup) outcome = 'foto_duplicada';
else if (!legible) outcome = 'ilegible';
else               outcome = 'comprar';

return [{ json: { outcome, id_actividad_foto, ref, ref_raw, products,
  image_url: (photos.image_url||''),
  correo: prep.correo, celular: prep.celular, celular10: prep.celular10,
  wa_to: prep.wa_to, had_row: prep.had_row } }];

// A6 · Comprar + Aceptar — POST /retail/buy + POST /entries/accept
const helpers = this.helpers;
const API_KEY = $env.API_KEY;
const BASE = 'https://api.superlikerslabs.com/v1';
const ev = $('A6 · Evaluar Lectura').first().json;
const correo = $('Cargar Estado').first().json.correo;
const ref = ev.ref, products = ev.products, id_actividad_foto = ev.id_actividad_foto;

let buyStatus=null, buyBody=null, points=0, buyErr=null, buy_ok=false, ya_registrada=false;
try {
  const r = await helpers.httpRequest({ method:'POST', url:BASE+'/retail/buy',
    headers:{ 'Authorization':'Bearer '+API_KEY, 'Content-Type':'application/json' },
    body:{ api_key:API_KEY, campaign:'3z', distinct_id:correo, ref:ref, products:products },
    json:true, returnFullResponse:true, ignoreHttpStatusErrors:true, timeout:30000 });
  buyStatus=r.statusCode; buyBody=r.body;
  buy_ok = (buyStatus >= 200 && buyStatus < 300);
  const bobj = (buyBody && buyBody.object) ? buyBody.object : (buyBody||{});
  if (bobj && bobj.invoice && bobj.invoice.points != null) points = bobj.invoice.points;
  else if (bobj && bobj.points != null) points = bobj.points;
  const bblob = JSON.stringify(buyBody||{}).toLowerCase();
  ya_registrada = !buy_ok && (bblob.indexOf('ya') !== -1 && (bblob.indexOf('registr') !== -1 || bblob.indexOf('usad') !== -1 || bblob.indexOf('existe') !== -1)) || (buyStatus === 422);
} catch (e) { buyErr = e.message; }

let accStatus=null, accBody=null, execution_error=false, accErr=null;
if (buy_ok) {
  try {
    const r2 = await helpers.httpRequest({ method:'POST', url:BASE+'/entries/accept',
      headers:{ 'Authorization':'Bearer '+API_KEY, 'Content-Type':'application/json' },
      body:{ api_key:API_KEY, campaign:'3z', id:id_actividad_foto },
      json:true, returnFullResponse:true, ignoreHttpStatusErrors:true, timeout:30000 });
    accStatus=r2.statusCode; accBody=r2.body;
    const ablob = JSON.stringify(accBody||{}).toLowerCase();
    execution_error = ablob.indexOf('execution_error') !== -1;
  } catch (e) { accErr = e.message; execution_error = true; }
}

return [{ json: { points: Number(points)||0, buy_ok, ya_registrada, execution_error,
  ref, id_actividad_foto, correo,
  celular: ev.celular, celular10: ev.celular10, wa_to: ev.wa_to, had_row: ev.had_row,
  buyStatus, accStatus, buyErr, accErr } }];

